# pages/page_eda.pyimport streamlit as stimport plotly.express as pximport plotly.graph_objects as goimport pandas as pdimport numpy as npfrom utils.data_utils import load_eda_samplefrom config import MOIS_L, JOURSdef _safe_groupby(df: pd.DataFrame, group_col: str, target: str,                  agg: str = "mean", min_rows: int = 5) -> pd.DataFrame | None:    """    Effectue un groupby sécurisé.    Retourne None si le résultat est vide ou si la colonne est absente.    """    if group_col not in df.columns or target not in df.columns:        return None    result = df.groupby(group_col, observed=True)[target].agg(agg).reset_index()    result = result.dropna()    if len(result) < min_rows:        return None    return resultdef _check_col(df: pd.DataFrame, col: str) -> bool:    """Vérifie qu'une colonne existe et a des valeurs non-null."""    return col in df.columns and df[col].notna().sum() > 0def render():    st.markdown("""    <div class='page-header'>        <h1>📊 Analyse Exploratoire Interactive</h1>        <p>Basé sur un échantillon représentatif de la base batch_1.db</p>    </div>""", unsafe_allow_html=True)    # ── CHARGEMENT avec diagnostic visible ───────────────────    status = st.empty()    status.info("⏳ Chargement des données EDA...")    try:        df = load_eda_sample()    except Exception as e:        st.error(f"❌ Erreur lors du chargement : {e}")        st.exception(e)        st.stop()    if df is None or len(df) == 0:        st.error("❌ Le DataFrame chargé est vide. Vérifiez data/eda_sample.csv ou la base SQLite.")        st.stop()    status.success(f"✅ {len(df):,} vols chargés")    # ── DIAGNOSTIC COLONNES (affiché uniquement en mode debug) ─    with st.expander("🔍 Diagnostic du dataset (cliquez pour afficher)", expanded=False):        col_a, col_b = st.columns(2)        with col_a:            st.markdown("**Colonnes disponibles**")            st.write(sorted(df.columns.tolist()))        with col_b:            st.markdown("**Valeurs manquantes (%)**")            miss = (df.isnull().sum() / len(df) * 100).sort_values(ascending=False)            st.dataframe(miss[miss > 0].round(1).rename("NaN %"), use_container_width=True)        st.markdown("**Aperçu (5 premières lignes)**")        st.dataframe(df.head(), use_container_width=True)        st.markdown("**Statistiques RETARD_BIN**")        if "RETARD_BIN" in df.columns:            st.write(df["RETARD_BIN"].value_counts().rename("count"))        else:            st.warning("⚠️ RETARD_BIN absent du dataset")    # ── FILTRES ───────────────────────────────────────────────    with st.sidebar:        st.markdown("### 🔧 Filtres EDA")        if _check_col(df, "ANNEE"):            annees    = sorted(df["ANNEE"].dropna().unique().astype(int))            sel_ann   = st.multiselect("Années", annees, default=annees, key="eda_ann")        else:            sel_ann   = []        if _check_col(df, "NOM_COMPAGNIE"):            comps     = ["Toutes"] + sorted(df["NOM_COMPAGNIE"].dropna().unique())            sel_comp  = st.selectbox("Compagnie", comps, key="eda_comp")        else:            sel_comp  = "Toutes"        if _check_col(df, "PAYS_DEP"):            pays_l    = ["Tous"] + sorted(df["PAYS_DEP"].dropna().unique())            sel_pays  = st.selectbox("Pays départ", pays_l, key="eda_pays")        else:            sel_pays  = "Tous"    df_f = df.copy()    if sel_ann and _check_col(df_f, "ANNEE"):        df_f = df_f[df_f["ANNEE"].isin(sel_ann)]    if sel_comp != "Toutes" and _check_col(df_f, "NOM_COMPAGNIE"):        df_f = df_f[df_f["NOM_COMPAGNIE"] == sel_comp]    if sel_pays != "Tous" and _check_col(df_f, "PAYS_DEP"):        df_f = df_f[df_f["PAYS_DEP"] == sel_pays]    if len(df_f) == 0:        st.warning("⚠️ Aucune donnée après filtrage. Modifiez les filtres.")        st.stop()    st.caption(f"📊 Données affichées : **{len(df_f):,}** vols après filtrage")    lc = dict(plot_bgcolor="rgba(0,0,0,0)",               paper_bgcolor="rgba(0,0,0,0)",               font_color="#F0F4F8")    tab1, tab2, tab3, tab4 = st.tabs([        "⏱️ Temporel", "✈️ Compagnies", "🌍 Géographie", "💰 Coûts"    ])    # ═══════════════════════════════════════════════════════════    with tab1:        st.markdown("#### Analyse temporelle des retards")        # ── Taux par heure de départ ──────────────────────────        if _check_col(df_f, "HEURE_DEP_H") and _check_col(df_f, "RETARD_BIN"):            h_data = (df_f.groupby("HEURE_DEP_H", observed=True)["RETARD_BIN"]                      .mean().reset_index().dropna())            if len(h_data) > 0:                c1, c2 = st.columns(2)                with c1:                    fig = go.Figure(go.Bar(                        x=h_data["HEURE_DEP_H"],                        y=h_data["RETARD_BIN"] * 100,                        marker_color=[                            "#E74C3C" if v > 35 else                            "#F39C12" if v > 25 else "#2ECC71"                            for v in h_data["RETARD_BIN"] * 100                        ],                    ))                    fig.update_layout(**lc,                        title="Taux de retard par heure de départ",                        xaxis_title="Heure", yaxis_title="Taux (%)")                    st.plotly_chart(fig, use_container_width=True)            else:                st.info("Données insuffisantes pour HEURE_DEP_H.")            # ── Taux par jour de la semaine ───────────────────            if _check_col(df_f, "JOUR_SEM"):                with c2 if "c2" in dir() else st:                    jour_d = (df_f.groupby("JOUR_SEM", observed=True)["RETARD_BIN"]                              .mean().reset_index().dropna())                    jour_d["Jour"] = jour_d["JOUR_SEM"].apply(                        lambda x: JOURS[int(x)] if pd.notna(x) and 0<=int(x)<=6 else "?")                    if len(jour_d) > 0:                        c1, c2 = st.columns(2)                        with c2:                            fig2 = px.bar(                                jour_d, x="Jour", y="RETARD_BIN",                                color="RETARD_BIN",                                color_continuous_scale="RdYlGn_r",                                title="Taux par jour de la semaine",                                labels={"RETARD_BIN":"Taux"},                                text_auto=".1%",                            )                            fig2.update_layout(**lc, coloraxis_showscale=False)                            st.plotly_chart(fig2, use_container_width=True)        else:            st.warning("⚠️ Colonnes HEURE_DEP_H ou RETARD_BIN absentes ou vides.")        # ── Heatmap Mois × Année ──────────────────────────────        if _check_col(df_f,"MOIS") and _check_col(df_f,"ANNEE") and _check_col(df_f,"RETARD_BIN"):            try:                pivot_my = (df_f.pivot_table(                    index="MOIS", columns="ANNEE",                    values="RETARD_BIN", aggfunc="mean") * 100)                if pivot_my.shape[0] > 0 and pivot_my.shape[1] > 0:                    pivot_my = pivot_my.dropna(how="all")                    valid_idx = [i for i in pivot_my.index                                 if pd.notna(i) and 1<=int(i)<=12]                    pivot_my  = pivot_my.loc[valid_idx]                    pivot_my.index = [MOIS_L[int(i)-1] for i in pivot_my.index]                    fig3 = px.imshow(                        pivot_my, text_auto=".1f",                        color_continuous_scale="RdYlGn_r",                        title="Heatmap Mois × Année — Taux retard (%)",                        aspect="auto",                    )                    fig3.update_layout(**lc)                    st.plotly_chart(fig3, use_container_width=True)                else:                    st.info("Données insuffisantes pour la heatmap Mois × Année.")            except Exception as e:                st.warning(f"⚠️ Heatmap Mois×Année impossible : {e}")        else:            st.info("Colonnes MOIS, ANNEE ou RETARD_BIN insuffisantes pour la heatmap.")        # ── Taux par créneau horaire ──────────────────────────        if _check_col(df_f, "CRENEAU") and _check_col(df_f, "RETARD_BIN"):            try:                cr = (df_f.groupby("CRENEAU", observed=True)["RETARD_BIN"]                      .agg(["mean","count"]).reset_index().dropna())                if len(cr) > 0:                    fig4 = px.bar(                        cr, x="CRENEAU", y="mean",                        color="mean", color_continuous_scale="RdYlGn_r",                        title="Taux de retard par créneau horaire",                        labels={"mean":"Taux","CRENEAU":"Créneau"},                        text_auto=".1%",                    )                    fig4.update_layout(**lc, coloraxis_showscale=False,                                       xaxis_tickangle=-20)                    st.plotly_chart(fig4, use_container_width=True)            except Exception as e:                st.warning(f"⚠️ Graphique créneau impossible : {e}")    # ═══════════════════════════════════════════════════════════    with tab2:        st.markdown("#### Analyse par compagnie")        if not _check_col(df_f, "NOM_COMPAGNIE"):            st.warning("⚠️ Colonne NOM_COMPAGNIE absente.")        elif not _check_col(df_f, "RETARD_BIN"):            st.warning("⚠️ Colonne RETARD_BIN absente.")        else:            n = st.slider("Nb compagnies", 5, min(20, df_f["NOM_COMPAGNIE"].nunique()), 10,                          key="eda_ncomp")            try:                cs = (df_f.groupby("NOM_COMPAGNIE", observed=True)                      .agg(taux=("RETARD_BIN","mean"),                           nb=("RETARD_BIN","count"),                           ret_moy=("RETARD_ARRIVEE","mean"))                      .reset_index()                      .sort_values("taux", ascending=False)                      .head(n)                      .dropna(subset=["taux"]))                cs["taux_pct"] = cs["taux"] * 100                if len(cs) == 0:                    st.info("Pas assez de données compagnie après filtrage.")                else:                    c1, c2 = st.columns(2)                    with c1:                        fig = px.bar(                            cs.sort_values("taux_pct"),                            x="taux_pct", y="NOM_COMPAGNIE",                            orientation="h",                            color="taux_pct",                            color_continuous_scale="RdYlGn_r",                            title=f"Top {n} — Taux de retard",                            text_auto=".1f",                        )                        fig.update_layout(**lc, coloraxis_showscale=False)                        st.plotly_chart(fig, use_container_width=True)                    with c2:                        fig2 = px.scatter(                            cs, x="nb", y="taux_pct",                            size=cs["nb"].clip(lower=1),                            color="taux_pct",                            hover_name="NOM_COMPAGNIE",                            color_continuous_scale="RdYlGn_r",                            title="Volume vs Taux de retard",                        )                        fig2.update_layout(**lc, coloraxis_showscale=False)                        st.plotly_chart(fig2, use_container_width=True)                    # Retard moyen                    if _check_col(cs, "ret_moy"):                        fig3 = px.bar(                            cs.dropna(subset=["ret_moy"]),                            x="NOM_COMPAGNIE", y="ret_moy",                            color="ret_moy", color_continuous_scale="Oranges",                            title="Retard moyen par compagnie (min)",                            text_auto=".0f",                        )                        fig3.update_layout(**lc, coloraxis_showscale=False,                                           xaxis_tickangle=-30)                        st.plotly_chart(fig3, use_container_width=True)            except Exception as e:                st.error(f"❌ Erreur tab Compagnies : {e}")                st.exception(e)    # ═══════════════════════════════════════════════════════════    with tab3:        st.markdown("#### Analyse géographique")        if _check_col(df_f, "PAYS_DEP") and _check_col(df_f, "RETARD_BIN"):            try:                pays_s = (df_f.groupby("PAYS_DEP", observed=True)["RETARD_BIN"]                          .agg(["mean","count"]).reset_index())                pays_s.columns = ["PAYS","Taux","Volume"]                pays_s = pays_s[pays_s["Volume"] > 3].sort_values("Taux", ascending=False).head(20)                if len(pays_s) > 0:                    fig = px.bar(                        pays_s.sort_values("Taux"),                        x="Taux", y="PAYS", orientation="h",                        color="Taux", color_continuous_scale="RdYlGn_r",                        title="Taux de retard par pays de départ",                        text_auto=".1%",                    )                    fig.update_layout(**lc, coloraxis_showscale=False,                                      xaxis_tickformat=".0%")                    st.plotly_chart(fig, use_container_width=True)                else:                    st.info("Données insuffisantes par pays (minimum 3 vols par pays).")            except Exception as e:                st.warning(f"⚠️ Graphique pays impossible : {e}")        if _check_col(df_f, "SEGMENT_DIST") and _check_col(df_f, "RETARD_BIN"):            try:                seg = (df_f.groupby("SEGMENT_DIST", observed=True)["RETARD_BIN"]                       .mean().reset_index().dropna())                if len(seg) > 0:                    fig2 = px.bar(                        seg, x="SEGMENT_DIST", y="RETARD_BIN",                        color="RETARD_BIN", color_continuous_scale="RdYlGn_r",                        title="Taux de retard par segment de distance",                        labels={"RETARD_BIN":"Taux","SEGMENT_DIST":"Segment"},                        text_auto=".1%",                    )                    fig2.update_layout(**lc, coloraxis_showscale=False)                    st.plotly_chart(fig2, use_container_width=True)            except Exception as e:                st.warning(f"⚠️ Graphique segment distance impossible : {e}")        # Carte si coordonnées disponibles        if all(_check_col(df_f, c) for c in ["LAT_DEP","LON_DEP","AP_DEP"]):            try:                ap_geo = (df_f.groupby(["AP_DEP","LAT_DEP","LON_DEP"], observed=True)                          .agg(nb=("RETARD_BIN","count"), taux=("RETARD_BIN","mean"))                          .reset_index()                          .dropna(subset=["LAT_DEP","LON_DEP"]))                ap_geo["Taux_pct"] = (ap_geo["taux"] * 100).round(1)                ap_geo["size"]     = (ap_geo["nb"] / ap_geo["nb"].max() * 30).clip(lower=3)                if len(ap_geo) > 2:                    fig3 = px.scatter_geo(                        ap_geo,                        lat="LAT_DEP", lon="LON_DEP",                        size="size", color="Taux_pct",                        hover_name="AP_DEP",                        color_continuous_scale="RdYlGn_r",                        projection="natural earth",                        title="Carte des aéroports de départ",                    )                    fig3.update_layout(**lc,                        geo=dict(bgcolor="rgba(0,0,0,0)",landcolor="#1F2937",                                 showocean=True,oceancolor="#0A0E1A",                                 showcountries=True,countrycolor="#374151"))                    st.plotly_chart(fig3, use_container_width=True)            except Exception as e:                st.warning(f"⚠️ Carte impossible : {e}")    # ═══════════════════════════════════════════════════════════    with tab4:        st.markdown("#### Analyse des coûts")        if not _check_col(df_f, "COUT_TOTAL"):            st.warning("⚠️ Colonne COUT_TOTAL absente.")        else:            df_cout = df_f[df_f["COUT_TOTAL"] > 0].copy()            if len(df_cout) < 10:                st.info("Trop peu de données de coût disponibles.")            else:                c1, c2 = st.columns(2)                with c1:                    try:                        fig = px.histogram(                            df_cout, x="COUT_TOTAL", nbins=40,                            color="RETARD_BIN",                            color_discrete_map={0:"#2ECC71",1:"#E74C3C"},                            title="Distribution du coût total",                            labels={"COUT_TOTAL":"Coût (€)","RETARD_BIN":"Retardé"},                            barmode="overlay", opacity=0.7,                        )                        fig.update_layout(**lc)                        st.plotly_chart(fig, use_container_width=True)                    except Exception as e:                        st.warning(f"⚠️ Histogramme coût impossible : {e}")                with c2:                    try:                        seg_c = (df_f.groupby("RETARD_BIN", observed=True)                                 .agg(cout=("COUT_TOTAL","mean")).reset_index().dropna())                        seg_c["label"] = seg_c["RETARD_BIN"].map({0:"À l'heure",1:"Retardé",                                                                   "0":"À l'heure","1":"Retardé"})                        if len(seg_c) > 0:                            fig2 = px.bar(                                seg_c, x="label", y="cout",                                color="label",                                color_discrete_map={"À l'heure":"#2ECC71","Retardé":"#E74C3C"},                                title="Coût moyen selon le retard",                                text_auto=",.0f",                            )                            fig2.update_layout(**lc, showlegend=False)                            st.plotly_chart(fig2, use_container_width=True)                    except Exception as e:                        st.warning(f"⚠️ Barplot coût impossible : {e}")